<script setup>
import { ref, onMounted, onBeforeUnmount } from "vue";

const isScrolled = ref(false);
const isMenuOpen = ref(false);

const skillGroups = {
    "Scientific Research": [
        { name: "Neuroimaging", icon: "bi bi-brain" },
        { name: "Community Research", icon: "bi bi-people" },
        { name: "MATLAB", icon: "bi bi-code-square" },
        { name: "R Statistics", icon: "bi bi-graph-up-arrow" }
    ],
    "Software Engineering": [
        { name: "Python", icon: "bi bi-braces" },
        { name: "Vue.js", icon: "bi bi-gem" },
        { name: "Flask", icon: "bi bi-server" },
        { name: "PostgreSQL", icon: "bi bi-database" },
        { name: "GitHub", icon: "bi bi-github" }
    ],
    "Data & AI": [
        { name: "TensorFlow", icon: "bi bi-cpu" },
        { name: "scikit-learn", icon: "bi bi-diagram-3" },
        { name: "Pandas", icon: "bi bi-table" },
        { name: "Computer Vision", icon: "bi bi-eye" }
    ]
};

const getCategoryIcon = (category) => {
    const icons = {
        "Scientific Research": "bi bi-mortarboard",
        "Software Engineering": "bi bi-code-slash",
        "Data & AI": "bi bi-bar-chart-steps"
    };
    return icons[category] || "bi bi-stars";
};

const handleScroll = () => {
    const scrollY = window.scrollY;
    isScrolled.value = scrollY > 50;
    
    // Skip parallax on mobile for stability
    if (window.innerWidth < 768) return;

    const progress = Math.min(scrollY / 400, 1);
    const nav = document.querySelector('.glass-nav');
    if (nav) {
        nav.style.setProperty('--nav-width', `${90 + (progress * 10)}%`);
        nav.style.setProperty('--nav-max-width', `${1000 + (progress * 1000)}px`);
        nav.style.setProperty('--nav-top', `${1.5 - (progress * 1.5)}rem`);
        nav.style.setProperty('--nav-radius', `${(1 - progress) * 50}px`);
        nav.style.setProperty('--nav-padding', `${0.75 + (progress * 0.25)}rem ${2 + (progress * 2)}rem`);
    }
};

const scrollTo = (id) => {
    const el = document.getElementById(id);
    if (el) {
        window.scrollTo({
            top: el.offsetTop + 100,
            behavior: "smooth"
        });
    }
};

onMounted(() => {
    window.addEventListener("scroll", handleScroll);
    
    // Intersection Observer for reveal animations
    const observer = new IntersectionObserver((entries) => {
        entries.forEach(entry => {
            if (entry.isIntersecting) {
                entry.target.classList.add("active");
            }
        });
    }, { threshold: 0.1 });

    document.querySelectorAll(".reveal").forEach(el => observer.observe(el));
});

onBeforeUnmount(() => {
    window.removeEventListener("scroll", handleScroll);
});
</script>

